import { Server } from "@modelcontextprotocol/sdk/server/index.js";
import { StdioServerTransport } from "@modelcontextprotocol/sdk/server/stdio.js";

const server = new Server({
  name: "meu-server",
  version: "1.0.0",
}, {
  capabilities: { tools: {} }
});

// Registrar ferramenta
server.setRequestHandler(ListToolsRequestSchema, async () => ({
  tools: [{
    name: "consultar_api",
    description: "Consulta nossa API interna",
    inputSchema: {
      type: "object",
      properties: {
        endpoint: { type: "string" },
        params: { type: "object" }
      }
    }
  }]
}));

// Implementar ferramenta
server.setRequestHandler(CallToolRequestSchema, async (request) => {
  if (request.params.name === "consultar_api") {
    const result = await fetch(`https://api.minha-empresa.com/${request.params.arguments.endpoint}`);
    return { content: [{ type: "text", text: JSON.stringify(await result.json()) }] };
  }
});

const transport = new StdioServerTransport();
await server.connect(transport);
